// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
// NEW: Import danh sách loài. Bạn cần tạo file này.
import speciesData from '../data/speciesData';

// --- COMPONENT CHÍNH ---
function WoodDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  const [farmDetails, setFarmDetails] = useState(null);
  const [activities, setActivities] = useState([]);
  const [speciesOptions, setSpeciesOptions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // UPDATED: Tách state để quản lý logic mới
  const [formData, setFormData] = useState({
    speciesName: '',      // Sẽ chứa tên lâm sản cuối cùng để gửi đi
    scientificName: '',   // Sẽ chứa tên khoa học cuối cùng để gửi đi
    date: '',
    quantity: 0,
    unit: '',
    type: '',
    reason: '',
    source: '',
    destination: '',
    verifiedBy: '',
  });

  // NEW: State để điều khiển giao diện
  const [selectedSpecies, setSelectedSpecies] = useState(''); // Giá trị của dropdown "Tên lâm sản mới"
  const [isManualEntry, setIsManualEntry] = useState(false); // Trạng thái có đang nhập tay hay không

  const fetchData = useCallback(async () => { /* ... giữ nguyên logic fetchData ... */ }, [farmId, token]);
  useEffect(() => { fetchData(); }, [fetchData]);

  // --- CÁC HÀM XỬ LÝ SỰ KIỆN ---

  // Hàm xử lý chung cho các ô input thông thường
  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };
  
  // NEW: Hàm xử lý riêng cho dropdown "Tên lâm sản mới"
  const handleSpeciesSelectionChange = (e) => {
    const value = e.target.value;
    setSelectedSpecies(value);

    if (value === 'manual') {
      setIsManualEntry(true);
      // Xóa dữ liệu cũ khi chuyển sang nhập tay
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else if (value === '') {
      setIsManualEntry(false);
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else {
      setIsManualEntry(false);
      const matched = speciesData.find(s => s.name === value);
      if (matched) {
        // Tự động điền cả speciesName và scientificName vào formData
        setFormData(prev => ({
          ...prev,
          speciesName: matched.name,
          scientificName: matched.scientificName,
        }));
      }
    }
  };
  
  const handleAddActivity = async (e) => {
    e.preventDefault();
    // Logic gửi form không cần thay đổi nhiều vì formData đã chứa dữ liệu đúng
    // ...
  };

  const handleDeleteActivity = async (activityId) => { /* ... giữ nguyên ... */ };

  return (
    <div className="form-container">
      {/* ... các phần style và hiển thị thông tin cơ sở giữ nguyên ... */}

      <h3>Thêm bản ghi nhập/xuất mới:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          {/* KHU VỰC ĐĂNG KÝ MỚI LÂM SẢN */}
          <div className="form-group-full-width" style={{ gridColumn: '1 / -1', border: '1px solid #007bff', padding: '15px', borderRadius: '8px' }}>
            <label style={{ fontWeight: 'bold', display: 'block', marginBottom: '10px', color: '#007bff' }}>
              Đăng ký mới lâm sản
            </label>
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="speciesSelection">Tên lâm sản mới:</label>
                <select 
                  id="speciesSelection"
                  name="speciesSelection"
                  value={selectedSpecies}
                  onChange={handleSpeciesSelectionChange}
                  required
                >
                  <option value="">-- Chọn hoặc nhập tay --</option>
                  {speciesData.map((species, index) => (
                    <option key={index} value={species.name}>{species.name}</option>
                  ))}
                  <option value="manual">--- Nhập tay... ---</option>
                </select>
              </div>

              {/* Chỉ hiển thị khi đã chọn 1 loài (không phải nhập tay) */}
              {!isManualEntry && selectedSpecies && selectedSpecies !== 'manual' && (
                <div className="form-group">
                  <label>Tên khoa học (tự động):</label>
                  <input
                    type="text"
                    value={formData.scientificName}
                    readOnly
                    disabled
                    className="readonly-input"
                  />
                </div>
              )}

              {/* Chỉ hiển thị khi chọn "Nhập tay" */}
              {isManualEntry && (
                <>
                  <div className="form-group">
                    <label htmlFor="speciesName">Tên lâm sản (nhập tay):</label>
                    <input
                      type="text"
                      id="speciesName"
                      name="speciesName"
                      value={formData.speciesName}
                      onChange={handleFormChange}
                      placeholder="Nhập tên lâm sản mới..."
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label htmlFor="scientificName">Tên khoa học (nhập tay):</label>
                    <input
                      type="text"
                      id="scientificName"
                      name="scientificName"
                      value={formData.scientificName}
                      onChange={handleFormChange}
                      placeholder="Nhập tên khoa học..."
                    />
                  </div>
                </>
              )}
            </div>
          </div>
          
          {/* CÁC TRƯỜNG CÒN LẠI CỦA FORM */}
          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input type="date" name="date" value={formData.date} onChange={handleFormChange} required />
          </div>

          <div className="form-group">
            <label>Loại giao dịch:</label>
            <select name="type" value={formData.type} onChange={handleFormChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="import">Nhập</option>
              <option value="export">Xuất</option>
            </select>
          </div>
          
          {/* ... các trường khác như Số lượng, Đơn vị, Nguồn gốc v.v... */}

        </div>
        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      {/* ... BẢNG LỊCH SỬ HOẠT ĐỘNG ... */}
    </div>
  );
}

export default WoodDetail;
